import sys
sys.setrecursionlimit(1 << 25)

def solve(n: int, edges: list[list[int]], k: int) -> int:
    max_w = max(e[2] for e in edges)

    def count_components(X):
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            if w <= X:
                adj[u].append(v)
                adj[v].append(u)
        visited = [False] * n
        components = 0
        for i in range(n):
            if not visited[i]:
                components += 1
                queue = [i]
                visited[i] = True
                while queue:
                    node = queue.pop(0)
                    for neighbor in adj[node]:
                        if not visited[neighbor]:
                            visited[neighbor] = True
                            queue.append(neighbor)
        return components

    low = 0
    high = max_w
    answer = max_w
    while low <= high:
        mid = (low + high) // 2
        m = count_components(mid)
        if m <= k:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1
    return answer
